def unique_values(lst):
    return list(set(lst))

numbers = [1, 2, 2, 3, 3, 3, 4]
print(unique_values(numbers))  # [1, 2, 3, 4]

# To preserve original order:
def unique_ordered(lst):
    seen = set()
    result = []
    for x in lst:
        if x not in seen:
            seen.add(x)
            result.append(x)
    return result
```

```python
def average(numbers):
    if not numbers:
        return 0
    return sum(numbers) / len(numbers)

scores = [78, 85, 92, 65, 88]
print(f'Average: {average(scores):.1f}')  # Average: 81.6
```

```python
def find_largest(numbers):
    if not numbers:
        return None
    largest = numbers[0]
    for n in numbers:
        if n > largest:
            largest = n
    return largest

prices = [450, 230, 890, 120, 670]
print(find_largest(prices))  # 890
# Or simply: max(prices)
```

